import React from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";

const BusCharts = ({ buses }) => {
  // Aggregate data by status
  const ghostCount = buses.filter((bus) => bus.status === "Ghost").length;
  const normalCount = buses.filter((bus) => bus.status === "Normal").length;

  const chartData = [
    { name: "Current", Ghost: ghostCount, Normal: normalCount },
  ];

  return (
    <div style={{ width: "100%", height: 300, marginTop: "20px" }}>
      <ResponsiveContainer>
        <LineChart
          data={chartData}
          margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
        >
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis />
          <Tooltip />
          <Legend />
          <Line type="monotone" dataKey="Ghost" stroke="red" />
          <Line type="monotone" dataKey="Normal" stroke="green" />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default BusCharts;
